}

.login-page__form :deep(.el-input__inner) {
  color: #f1f5f9;
  height: 46px;
}

.login-page__form :deep(.el-input__inner::placeholder) {
  color: rgba(100, 116, 139, 0.5);
}

.login-page__form :deep(.el-input__prefix) {
  color: rgba(100, 116, 139, 0.6);
  margin-right: 8px;
}

/* ===== 验证码区域 ===== */
.login-page__captcha {
  display: grid;
